import { checkPassword } from "@/lib/hashing";
import { cookies } from "next/headers";

export default async function PasswordChange2Page() {
    const keksiky = await cookies();
    const code = keksiky.get("number")?.value ?? "";

    async function verify(input: string) {
        const isCodeValid = await checkPassword(input, code);

        if (isCodeValid) {
            window.location.href = "/password_change3";
        }
    }

    return (
        <div className="card max-w-md mx-auto flex flex-col gap-4">
            <h1>Verify Code</h1>
                <input
                    placeholder="Enter code"
                    className="border p-2 rounded"
                />
            <p>Check your email for the 4-digit code.</p>
            <button>Verify</button>
        </div>
    );
}
